{"file_text": "from flask import Flask, render_template, request, redirect, url_for, flash
from database import db
from models import URL
import os

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///urls.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False
app.config['SECRET_KEY'] = 'secret_key'

db.init_app(app)

with app.app_context():
    db.create_all()

@app.route('/', methods=['GET', 'POST'])
def index():
    if request.method == 'POST':
        original_url = request.form.get('url')
        if not original_url:
            flash('URL is required!')
            return redirect(url_for('index'))

        existing_url = URL.query.filter_by(original_url=original_url).first()
        if existing_url:
            short_url = existing_url.short_url
        else:
            new_url = URL(original_url=original_url)
            db.session.add(new_url)
            db.session.commit()
            short_url = new_url.short_url

        return render_template('index.html', short_url=request.host_url + short_url)

    return render_template('index.html')

@app.route('/<short_url>')
def redirect_to_url(short_url):
    url_entry = URL.query.filter_by(short_url=short_url).first_or_404()
    return redirect(url_entry.original_url)

if __name__ == '__main__':
    app.run(debug=True)
